import React, { useState, useEffect, useRef, useCallback } from "react";
import BarWave from "react-cssfx-loading/lib/BarWave";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import { createGuestId } from "../../utilities/utilities";
import CardContainer from "../../components/CardContainer";
import Header from "../../components/Header";
import SinglePollContainer from "../../components/SinglePollContainer";
import PersonPollCarousel from "../../components/PersonPollMob";
import Tab from "../../components/Tab";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
import useFetch from "../../hooks/useFetch";
import { settings, centerSetting } from "../../common/carouselSetting";

const Home = () => {
  //Variables
  const user = localStorage.getItem("user");
  const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");
  const numberOfPollVoted = localStorage.getItem("numberOfPollVoted");
  const numberOfPollLiked = localStorage.getItem("numberOfPollLiked");

  //State
  const [loading, setLoading] = useState(false);
  const [dataPersonal, setDataPersonal] = useState([]);
  const [page, setPage] = React.useState(1);
  const { isLoading, error, data, hasMore } = useFetch(page);

  //Called Ref For Infinite Scroller
  const observer = useRef();

  //last Element Ref
  const lastElementRef = useCallback(
    (node) => {
      if (isLoading) return;
      if (observer.current) observer.current.disconnect();
      observer.current = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting && hasMore) {
          if (page != 0) {
            setPage((prev) => prev + 1);
          } else {
            setPage((prev) => prev + 2);
          }
        }
      });
      if (node) observer.current.observe(node);
    },
    [isLoading, hasMore]
  );

  useEffect(() => {
    if (!GUEST_USER_ID) {
      createGuestId();
    }
    if (!numberOfPollVoted) {
      localStorage.setItem("numberOfPollVoted", 0);
    }
    if (!numberOfPollLiked) {
      localStorage.setItem("numberOfPollLiked", 0);
    }
    fetchdata();
  }, []);

  const fetchdata = async () => {
    let param;
    param = {
      status: 1,
      guest_user_id: GUEST_USER_ID,
      filter_case:"question_type"
    };
    var res = await POST(APIs.POLLlistquestion3+"?limit=25&page=1", param);
    if (res.status === 200) {
      if (res.data){
        // console.log('res from api',res.data);
        setDataPersonal(res.data);
      } 
    }
    setLoading(true);
  };

  return (
    <>
      <Header />
      {loading ? (
        <>
          <div className="container">
            <Slider {...settings}>
              {dataPersonal.map((val, index) => {
                  
                // val.question_type == 3 ? <div className="AdDiv">AD</div> : null
                return <SinglePollContainer onVote={fetchdata} banner_image={val.answers[0].image} val={val} key={index} />;
              })}
            </Slider>
          </div>

          {/* <div className="container slider center mob-slider">
            <Slider {...centerSetting}>
              {dataPersonal.map((val, index) => {
                return <PersonPollCarousel onVote={fetchdata} val={val} key={index} />;
              })}
            </Slider>
          </div> */}
          {/* <div className="hrLine" /> */}
          <Tab />
          {data.map((val, index) => {
            return (
              <div ref={lastElementRef}>
                <CardContainer val={val} key={index} />
              </div>
            );
          })}
        </>
      ) : (
        <div className="loadingDiv">
          <BarWave color="#4BD97E" width="100px" height="100px" />
        </div>
      )}
    </>
  );
};

export default Home;
