import React, { useState, useEffect } from "react";
import axios from "axios";

function useFetch(pageNum) {
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(false);
  const [data, setData] = useState([]);
  const [hasMore, setHasMore] = useState(false);
  const user = localStorage.getItem("user");
  const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");

  useEffect(() => {
    setIsLoading(true);
    setError(false);
    let param;
    if (user) {
      param = {
        status: 1,
        user_id: JSON.parse(user)._id,
        filter_case:"statusnotquestion3"
      };
    } else {
      param = {
        status: 1,
        guest_user_id: GUEST_USER_ID,
        filter_case:"statusnotquestion3"
      };
    }
    axios
      .post(
        `https://api.pollhole.com/v1/poll/list?limit=${10}&page=${
          pageNum == 0 ? pageNum + 1 : pageNum
        }`,
        {
          ...param,
        }
      )
      .then((res) => {
        setData((prev) => {
          return [...new Set([...prev, ...res.data.data])];
        });
        setHasMore(res.data.data.length > 0);
        setIsLoading(false);
      })
      .catch((err) => {
        if (axios.isCancel(err)) return;
        setError(err);
      });
  }, [pageNum]);

  return { isLoading, error, data, hasMore };
}

export default useFetch;
